```python
import json

def evaluate_experts(experts):
    # Extract verdicts and explanations
    verdicts = [expert['verdict'] == 'True' for expert in experts]
    explanations = [expert['explanation'] for expert in experts]

    # Calculate weighted sum of verdicts
    weighted_sum = sum(expert['weight'] * (1 if verdict else 0) for expert, verdict in zip(experts, verdicts))

    # Determine the majority verdict
    majority_verdict = 'True' if weighted_sum > 0 else 'False'

    # Determine the explanation
    if majority_verdict == 'True':
        # Find the first explanation that supports the majority verdict
        for explanation in explanations:
            if 'Mitt Romney drove to Canada with the family dog Seamus strapped to the roof of the car' in explanation:
                return {'verdict': majority_verdict, 'explanation': explanation}
    else:
        # If the majority verdict is 'False', return a default explanation
        return {'verdict': majority_verdict, 'explanation': 'The majority of experts disagree with the claim.'}

